module.exports = {
  config: {
    name: 'alluid',
    aliases: ["uidall","allid"],
    version: '1.0.0',
    permission: 0,
    prefix: true,
    premium: false,
    category: 'Utility',
    description: 'New command',
    usage: 'alluid [args]',
    credits: 'CHAND',
    cooldowns: 10,
    adminOnly: false
  },
  
  run: async function ({ api, event, args, Users }) {
    function reply(d) {
      api.sendMessage(d, event.threadID, event.messageID)
    }
    var ep = event.participantIDs;
    let msg = ""
    let msgs = ""
    let m = 0;
    for (let i of ep) {
      m += 1;
      const name = await Users.getNameUser(i);
      msg += m+" ❯ "+name+"\n🅤𝐬𝐞𝐫 𝐢𝐝 : "+i+"\n🅕𝐛 𝐥𝐢𝐧𝐤: https://facebook.com/"+i+"\n\n";
    }
    msgs += "━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n\n🅐𝐥𝐥 𝐮𝐬𝐞𝐫𝐬 𝐢𝐧 𝐭𝐡𝐢𝐬 𝐠𝐫𝐨𝐮𝐩\n\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n\n"+msg;
    reply(msgs)
  }
};